1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  // Rule 1: Underpopulation - Live cell with < 2 neighbors dies
6	  it("should kill a live cell with no neighbors", () => {
7	    // Single live cell at origin with no neighbors
8	    const grid: Array<[number, number]> = [[0, 0]];
9	    const result = nextGeneration(grid);
10	    // Cell should die from underpopulation
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill a live cell with one neighbor", () => {
14	    // Two live cells at [0,0] and [1,0] - each has exactly one neighbor
15	    const grid: Array<[number, number]> = [[0, 0], [1, 0]];
16	    const result = nextGeneration(grid);
17	    // Both cells should die from underpopulation (< 2 neighbors)
18	    expect(result).toEqual([]);
19	  });
20	
21	  // Rule 2: Survival - Live cell with 2-3 neighbors survives
22	  it("should keep a live cell alive with two neighbors", () => {
23	    // Three cells in a line: [0,0] [1,0] [2,0]
24	    // [1,0] (middle) has exactly 2 neighbors: [0,0] and [2,0]
25	    const grid: Array<[number, number]> = [[0, 0], [1, 0], [2, 0]];
26	    const result = nextGeneration(grid);
27	    // Middle cell should survive with 2 neighbors (Rule 2)
28	    // End cells should die with 1 neighbor each (Rule 1)
29	    // After next generation, only middle cell survives
30	    expect(result).toEqual([[1, 0]]);
31	  });
32	  it("should keep a live cell alive with three neighbors", () => {
33	    // Four cells forming a square or line with center having 3 neighbors
34	    // Example: [0,0] [1,0] [2,0] [1,1]
35	    // [1,0] has neighbors at [0,0], [2,0], [1,1] = 3 neighbors
36	    const grid: Array<[number, number]> = [[0, 0], [1, 0], [2, 0], [1, 1]];
37	    const result = nextGeneration(grid);
38	    // [1,0] should survive with 3 neighbors (Rule 2: Survival)
39	    expect(result.some(([x, y]) => x === 1 && y === 0)).toBe(true);
40	  });
41	
42	  // Rule 3: Overpopulation - Live cell with > 3 neighbors dies
43	  it("should kill a live cell with four neighbors", () => {
44	    // Five cells: center cell [1,1] with four neighbors around it
45	    // [0,1], [1,0], [1,2], [2,1] form a + pattern around [1,1]
46	    const grid: Array<[number, number]> = [[1, 1], [0, 1], [1, 0], [1, 2], [2, 1]];
47	    const result = nextGeneration(grid);
48	    // Center cell [1,1] should die from overpopulation (4 neighbors > 3)
49	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
