1	const NEIGHBOR_OFFSETS: Array<[number, number]> = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1]
5	];
6	
7	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
8	  // Helper to check if a cell exists at coordinates
9	  const cellExists = (x: number, y: number): boolean => {
10	    return grid.some(([cx, cy]) => cx === x && cy === y);
11	  };
12	
13	  // Count neighbors for each cell
14	  const countNeighbors = (x: number, y: number): number => {
15	    return NEIGHBOR_OFFSETS.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
16	  };
17	
18	  // Apply rules: live cell with < 2 neighbors dies (Rule 1)
19	  return grid.filter(([x, y]) => countNeighbors(x, y) >= 2);
20	}
